156→void ALFPHexTile::ClearAllHighlights()
157→{
158→	// 隐藏覆盖层
159→	if (OverlaySpriteComponent)
160→	{
161→		OverlaySpriteComponent->SetVisibility(false);
162→	}
163→
164→	// 隐藏所有边缘
165→	for (int32 i = 0; i < EdgeSpriteComponents.Num(); i++)
166→	{
167→		if (EdgeSpriteComponents[i])
168→		{
169→			EdgeSpriteComponents[i]->SetVisibility(false);
170→		}
171→	}
172→}
