584→void ALFPHexGridManager::DrawDebugPath(const TArray<ALFPHexTile*>& Path, bool bPathFound)
585→{
586→	if (!GetWorld()) return;
587→
588→	const float DebugDuration = 5.0f; // 显示5秒
589→
590→	// 绘制起点和终点
591→	if (Path.Num() > 0) {
592→		// 起点：绿色球体
593→		DrawDebugSphere(
594→			GetWorld(),
595→			Path[0]->GetActorLocation() + FVector(0, 0, 20),
596→			15.0f, 12, FColor::Green, false, DebugDuration
597→		);
598→	}
599→
600→	if (bPathFound && Path.Num() > 1) {
601→		// 终点：蓝色球体
602→		DrawDebugSphere(
603→			GetWorld(),
604→			Path.Last()->GetActorLocation() + FVector(0, 0, 20),
605→			15.0f, 12, FColor::Blue, false, DebugDuration
606→		);
607→	}
608→
609→	// 绘制路径线段
610→	for (int32 i = 0; i < Path.Num() - 1; i++)
611→	{
612→		FVector StartLoc = Path[i]->GetActorLocation() + FVector(0, 0, 15);
613→		FVector EndLoc = Path[i + 1]->GetActorLocation() + FVector(0, 0, 15);
614→
615→		// 路径线：黄色
616→		DrawDebugLine(
617→			GetWorld(),
618→			StartLoc,
619→			EndLoc,
620→			FColor::Yellow,
621→			false,
622→			DebugDuration,
623→			0,
624→			3.0f // 线宽
625→		);
626→
627→		// 路径点：黄色球体
628→		DrawDebugSphere(
629→			GetWorld(),
630→			StartLoc,
631→			10.0f, 8, FColor::Yellow, false, DebugDuration
632→		);
633→	}
634→
635→	// 如果找到路径（但前面已经绘制过了，比如长度为1时）
636→	if (bPathFound && Path.Num() == 1) {
