698→// 世界坐标转换为六边形网格坐标
699→FVector2D ALFPHexGridManager::WorldToHexGridPosition(const FVector& WorldPosition, float InHexSize, float InVerticalScale)
700→{
701→	// 尖顶六边形布局参数
702→	const float HorizontalSpacing = InHexSize * 1.5f * InVerticalScale; // 水平间距（应用垂直缩放）
703→	const float VerticalSpacing = InHexSize * FMath::Sqrt(3.0f); // 垂直间距
704→
705→	// 计算原点位置
706→	FVector GridOrigin = GetActorLocation();
707→
708→	// 计算相对于网格原点的位置
709→	float RelX = WorldPosition.X - GridOrigin.X;
710→	float RelY = WorldPosition.Y - GridOrigin.Y;
711→
712→	// 转换为六边形网格坐标（近似）
713→	return FVector2D(
714→		RelX / HorizontalSpacing,
715→		RelY / VerticalSpacing
716→	);
717→}
