734→// 判断点是否在六边形内
735→bool ALFPHexGridManager::IsPointInHexagon(const FVector2D& Point, const FVector2D& Center, float InHexSize)
736→{
737→	// 坐标转换为相对于六边形中心的单位向量
738→	FVector2D relPoint = Point - Center;
739→
740→	// 尖顶六边形的顶点位置（从0度开始）
741→	static const TArray<FVector2D> vertices = [] {
742→		TArray<FVector2D> result;
743→		for (int i = 0; i < 6; i++) {
744→			float angle_deg = 60 * i; // 尖顶六边形从0度开始
745→			float angle_rad = FMath::DegreesToRadians(angle_deg);
746→			result.Add(FVector2D(FMath::Cos(angle_rad), FMath::Sin(angle_rad)));
747→		}
748→		return result;
749→		}();
750→
751→	// 判断点是否在六边形内（使用射线法）
752→	int crossings = 0;
753→	for (int i = 0; i < 6; i++) {
754→		int j = (i + 1) % 6;
755→		FVector2D v1 = vertices[i] * InHexSize;
756→		FVector2D v2 = vertices[j] * InHexSize;
757→
758→		// 检测边是否跨越y坐标
759→		if ((v1.Y > relPoint.Y) != (v2.Y > relPoint.Y)) {
760→			// 计算交点x坐标
761→			float intersectX = (v2.X - v1.X) * (relPoint.Y - v1.Y) / (v2.Y - v1.Y) + v1.X;
762→
763→			// 如果交点在点的右侧
764→			if (relPoint.X < intersectX) {
765→				crossings++;
766→			}
767→		}
768→	}
769→
770→	// 奇数次跨越表示在内部
771→	return (crossings % 2 == 1);
772→}
