918→// 优化后的四舍五入到最近六边形坐标
919→FLFPHexCoordinates ALFPHexGridManager::RoundToHex(float q, float r)
920→{
921→	// 转换为立方坐标
922→	float cube_x = q;
923→	float cube_z = r;
924→	float cube_y = -cube_x - cube_z;
925→
926→	// 分别四舍五入到最近整数
927→	int32 rx = FMath::RoundToInt(cube_x);
928→	int32 ry = FMath::RoundToInt(cube_y);
929→	int32 rz = FMath::RoundToInt(cube_z);
930→
931→	// 计算四舍五入误差
932→	float x_diff = FMath::Abs(rx - cube_x);
933→	float y_diff = FMath::Abs(ry - cube_y);
934→	float z_diff = FMath::Abs(rz - cube_z);
935→
936→	// 修正最大误差的分量
937→	if (x_diff > y_diff && x_diff > z_diff) {
938→		rx = -ry - rz;
939→	}
940→	else if (y_diff > z_diff) {
941→		ry = -rx - rz;
942→	}
943→	else {
944→		rz = -rx - ry;
945→	}
946→
947→	return FLFPHexCoordinates(rx, rz);
948→}
